const FeatureCard: FC<{ item: (typeof FEATURES)[number] }> = ({ item }) => {
  const handleClick = () => {
    const anchorId = `feature-${item.title.replace(/\s+/g, '-').toLowerCase()}`
    const anchorEle = document.getElementById(anchorId)
    if (anchorEle) {
      anchorEle.scrollIntoView({ block: 'start', behavior: 'smooth' })
    }
  }

  return (
    <Box
      onClick={handleClick}
      sx={{
        cursor: 'pointer',
        display: 'flex',
        flexDirection: 'column',
        borderRadius: 2,
        overflow: 'hidden',
        boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
        border: '1px solid rgba(0,0,0,0.06)',
        backgroundColor: '#fff',
        transition: 'transform .2s ease, box-shadow .2s ease',
        '&:hover': {
          transform: 'translateY(-2px)',
          boxShadow: '0 6px 16px rgba(0,0,0,0.10)'
        }
      }}>
      <Box
        component='img'
        src={item.img}
        alt={item.alt}
        sx={{ width: '100%', aspectRatio: '16 / 9', objectFit: 'cover' }}
        loading='lazy'
      />
      <Box sx={{ p: 1.5, textAlign: 'center', fontWeight: 600, fontSize: '0.95rem' }}>{item.title}</Box>
    </Box>
  )
}

